1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a cell alive that has exactly 2 live neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    const sorted = result.map(c => c.join(",")).sort();
20	    const expected = [[1, -1], [1, 0], [1, 1]].map(c => c.join(",")).sort();
21	    expect(sorted).toEqual(expected);
22	  });
23	  it("should keep a cell alive that has exactly 3 live neighbors (survival)", () => {
24	    // T-shape: cell (1,1) has exactly 3 live neighbors: (0,1), (2,1), (1,2)
25	    const result = nextGeneration([[0, 1], [1, 1], [2, 1], [1, 2]]);
26	    const resultSet = new Set(result.map(c => c.join(",")));
27	    // (1,1) should survive because it has exactly 3 live neighbors
28	    expect(resultSet.has("1,1")).toBe(true);
29	  });
30	  it("should kill a cell with more than 3 live neighbors (overpopulation)", () => {
31	    // Plus/cross pattern: center (1,1) has 4 live neighbors → dies
32	    const input: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
33	    const result = nextGeneration(input);
34	    const resultSet = new Set(result.map(c => c.join(",")));
35	    // (1,1) should be dead because it has 4 live neighbors (overpopulation)
36	    expect(resultSet.has("1,1")).toBe(false);
37	  });
38	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
39	    // L-shape in corner: (0,0), (0,1), (1,1)
40	    // Dead cell (1,0) has exactly 3 live neighbors: (0,0), (0,1), (1,1) → becomes alive
41	    const result = nextGeneration([[0, 1], [1, 1], [0, 0]]);
42	    const sorted = result.map(c => c.join(",")).sort();
43	    const expected = [[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")).sort();
44	    expect(sorted).toEqual(expected);
45	  });
46	  it.todo("should keep a block pattern unchanged as a still life");
47	  it.todo("should oscillate a blinker pattern to its alternate orientation");
48	});
