1	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
2	  const alive = new Set(liveCells.map(([x, y]) => `${x},${y}`));
3	  const neighborCounts = new Map<string, number>();
4	
5	  for (const [x, y] of liveCells) {
6	    for (let dx = -1; dx <= 1; dx++) {
7	      for (let dy = -1; dy <= 1; dy++) {
8	        if (dx === 0 && dy === 0) continue;
9	        const key = `${x + dx},${y + dy}`;
10	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
11	      }
12	    }
13	  }
14	
15	  const result: [number, number][] = [];
16	  for (const [key, count] of neighborCounts) {
17	    const isAlive = alive.has(key);
18	    if (count === 3 || (count === 2 && isAlive)) {
19	      const [x, y] = key.split(",").map(Number);
20	      result.push([x, y]);
21	    }
22	  }
23	
24	  return result;
25	}
